/* AI 防詐盾牌競賽版 Socket.IO 安全降級 shim
 * 若正式環境需要即時 WebSocket，請用官方 socket.io client 取代本檔。
 * 本 shim 的目的：避免缺檔導致攔截頁或戰情室整頁崩潰；API 輪詢仍可正常顯示資料。
 */
(function(global){
  if (global.io) return;
  global.io = function(){
    var handlers = {};
    var socket = {
      connected: false,
      on: function(name, cb){ handlers[name] = cb; return socket; },
      emit: function(){ return socket; },
      disconnect: function(){ socket.connected = false; if (handlers.disconnect) setTimeout(function(){handlers.disconnect();}, 0); return socket; }
    };
    setTimeout(function(){ if (handlers.connect_error) handlers.connect_error(new Error('Socket.IO client shim：即時通道未載入，請改用輪詢或放入官方 client。')); }, 30);
    return socket;
  };
})(typeof globalThis !== 'undefined' ? globalThis : this);
